    int m = grid.size();
    int n = grid[0].size();

    vector<vector<long long>> reversed_submatrix(k, vector<long long>(k));
    for (int i = 0; i < k; ++i) {
        int original_row = x + k - 1 - i;
        for (int j = 0; j < k; ++j) {
            reversed_submatrix[i][j] = grid[original_row][y + j];
